scriptContent:
# Chokepoint Renamed RMM Emulation
# Copy notepad.exe to campaign name, execute, outbound TCP
# Expected Detections: EID 1 (metadata mismatch), EID 11 (file in Downloads), EID 3 (outbound)

[CmdletBinding()]
param(
    [switch]$DryRun
)

Write-Host "=== Chokepoint Renamed RMM Emulation ===" -ForegroundColor Cyan
Write-Host "Emulating renamed RMM tool delivery and execution"

# Stage 1: Copy notepad.exe to campaign-named executable (EID 11 target)
Write-Host "\n[Stage 1] Creating renamed executable..."
$sourcePath = "C:\Windows\System32\notepad.exe"
$destDir = "$env:USERPROFILE\Downloads"
$destPath = Join-Path $destDir "AnyDesk.exe"

if (-not $DryRun) {
    try {
        if (Test-Path $sourcePath) {
            Copy-Item -Path $sourcePath -Destination $destPath -Force
            Write-Host "  Copied: $sourcePath -> $destPath" -ForegroundColor Yellow
            Write-Host "  Expected Detection: EID 11 (FileCreate in Downloads)" -ForegroundColor Cyan
        } else {
            Write-Host "  Source not found: $sourcePath" -ForegroundColor Red
        }
    } catch {
        Write-Host "  Error: $($_.Exception.Message)" -ForegroundColor Red
    }
} else {
    Write-Host "  [DryRun] Would copy notepad.exe to: $destPath" -ForegroundColor Magenta
}

# Stage 2: Execute renamed executable (EID 1 target - metadata mismatch)
Write-Host "\n[Stage 2] Executing renamed executable..."
if (-not $DryRun -and (Test-Path $destPath)) {
    try {
        Start-Process -FilePath $destPath -ArgumentList "/S" -Wait -NoNewWindow -ErrorAction SilentlyContinue
        Write-Host "  Action: Executed $destPath" -ForegroundColor Yellow
        Write-Host "  Expected Detection: EID 1 (metadata mismatch - notepad.exe running as AnyDesk.exe)" -ForegroundColor Cyan
    } catch {
        Write-Host "  Error: $($_.Exception.Message)" -ForegroundColor Red
    }
} else {
    Write-Host "  [DryRun] Would execute renamed executable" -ForegroundColor Magenta
}

# Stage 3: Outbound TCP connection (C2 simulation)
Write-Host "\n[Stage 3] Simulating outbound TCP connection..."
if (-not $DryRun) {
    try {
        $testHost = "httpbin.org"
        $testPort = 443
        $tcpClient = New-Object System.Net.Sockets.TcpClient
        $connect = $tcpClient.BeginConnect($testHost, $testPort, $null, $null)
        $wait = $connect.AsyncWaitHandle.WaitOne(3000, $false)
        if ($wait) {
            $tcpClient.EndConnect($connect)
            Write-Host "  Action: TCP connection to $testHost`:$testPort" -ForegroundColor Yellow
            Write-Host "  Expected Detection: EID 3 (Outbound network connection)" -ForegroundColor Cyan
            $tcpClient.Close()
        }
    } catch {
        Write-Host "  Connection failed (expected for emulation)" -ForegroundColor Red
    }
} else {
    Write-Host "  [DryRun] Would attempt outbound TCP connection" -ForegroundColor Magenta
}

# Cleanup
Write-Host "\n[Cleanup] Removing emulation artifacts..."
if (-not $DryRun -and (Test-Path $destPath)) {
    Remove-Item -Path $destPath -Force -ErrorAction SilentlyContinue
    Write-Host "  Removed: $destPath" -ForegroundColor Yellow
}

Write-Host "\n=== Emulation Complete ===" -ForegroundColor Cyan
Write-Host "Expected Detections:"
Write-Host "  - EID 11: File creation in Downloads folder" -ForegroundColor Green
Write-Host "  - EID 1: Process with metadata mismatch" -ForegroundColor Green
Write-Host "  - EID 3: Outbound network connection" -ForegroundColor Green
